/**
 * Shared helpers for promoting floating panels to the browser top layer via the
 * native Popover API.
 *
 * Floating panels (select dropdowns, tooltips, date pickers, ...) are rendered
 * inside each component's shadow DOM and positioned with `position: fixed`.
 * When such a component is placed inside another element that establishes a
 * containing block for fixed descendants (e.g. an ancestor with a `transform`,
 * like the animated `.ve-modal-panel`), the panel stops being positioned
 * relative to the viewport and gets clipped by that ancestor's `overflow`.
 *
 * Promoting the panel to the top layer with `popover="manual"` makes the
 * browser render it above all regular content with the viewport as its
 * containing block, so it escapes ancestor `transform`/`overflow`/clipping
 * while the node itself stays in its original shadow tree (styles and
 * `composedPath()`-based outside-click detection keep working).
 */
/**
 * The popover attribute value used for all VeDesign floating panels. `manual`
 * means the component fully controls open/close (no light-dismiss or toggling
 * from the browser), matching the existing imperative lifecycle.
 */
export declare const VE_PANEL_POPOVER = "manual";
/**
 * Whether the current environment supports the Popover API.
 */
export declare function supportsPopover(): boolean;
/**
 * Promote a panel element to the top layer.
 *
 * Safe to call repeatedly: it no-ops when the panel is missing, disconnected,
 * already shown, or when the Popover API is unavailable (graceful degradation
 * to the previous in-shadow `position: fixed` behaviour).
 */
export declare function showPanelPopover(panel: HTMLElement | null | undefined): void;
/**
 * Remove a panel element from the top layer.
 *
 * Safe to call repeatedly and on already-hidden or detached panels.
 */
export declare function hidePanelPopover(panel: HTMLElement | null | undefined): void;
